def fibonacci(n):
    if n < 0:
        return 0
    if n <= 1:
        return n

    # Karatsuba trick: replace a*(2b-a) with 3 squarings
    # a*(2b-a) = 2ab - a^2 = (a+b)^2 - a^2 - b^2 - a^2 = (a+b)^2 - 2*a^2 - b^2
    # So: compute a^2, b^2, (a+b)^2 -- all squarings, no general muls
    a, b = 0, 1
    for bit in range(n.bit_length() - 1, -1, -1):
        a_sq = a * a
        b_sq = b * b
        ab_sq = (a + b) * (a + b)
        c = ab_sq - a_sq - b_sq - a_sq  # 2ab - a^2 = (a+b)^2 - 2a^2 - b^2
        d = a_sq + b_sq
        if (n >> bit) & 1:
            a, b = d, c + d
        else:
            a, b = c, d
    return a
